 44→object ImportUtils {
 45→    /* A filename should be shortened if over this threshold */
 46→    private const val fileNameShorteningThreshold = 100
 47→
 48→    /**
 49→     * This code is used in multiple places to handle package imports
 50→     *
 51→     * @param context for use in resource resolution and path finding
 52→     * @param intent contains the file to import
 53→     * @return null if successful, otherwise error message
 54→     */
 55→    fun handleFileImport(context: Context, intent: Intent): ImportResult {
 56→        return FileImporter().handleFileImport(context, intent)
 57→    }
 58→
 59→    /**
 60→     * Makes a cached copy of the file selected on [intent] and returns its path
 61→     */
 62→    fun getFileCachedCopy(context: Context, intent: Intent): String? {
