 96→    @SuppressWarnings("WeakerAccess")
 97→    open class FileImporter {
 98→        /**
 99→         * This code is used in multiple places to handle package imports
100→         *
101→         * @param context for use in resource resolution and path finding
102→         * @param intent contains the file to import
103→         * @return null if successful, otherwise error message
104→         */
105→        fun handleFileImport(context: Context, intent: Intent): ImportResult {
106→            // This intent is used for opening apkg package files
107→            // We want to go immediately to DeckPicker, clearing any history in the process
108→            Timber.i("IntentHandler/ User requested to view a file")
109→            val extras = if (intent.extras == null) "none" else intent.extras!!.keySet().joinToString(", ")
110→            Timber.i("Intent: %s. Data: %s", intent, extras)
111→            return try {
112→                handleFileImportInternal(context, intent)
113→            } catch (e: Exception) {
114→                CrashReportService.sendExceptionReport(e, "handleFileImport")
115→                Timber.e(e, "failed to handle import intent")
116→                ImportResult.fromErrorString(context.getString(R.string.import_error_handle_exception, e.localizedMessage))
117→            }
118→        }
119→
120→        private fun handleFileImportInternal(context: Context, intent: Intent): ImportResult {
121→            val importPathUri = getDataUri(intent)
122→            return if (importPathUri != null) {
123→                handleContentProviderFile(context, intent, importPathUri)
124→            } else {
125→                ImportResult.fromErrorString(context.getString(R.string.import_error_handle_exception))
126→            }
127→        }
128→
129→        fun getFileCachedCopy(context: Context, uri: Uri): String? {
130→            val filename = ensureValidLength(getFileNameFromContentProvider(context, uri) ?: return null)
131→            val tempPath = Uri.fromFile(File(context.cacheDir, filename)).encodedPath!!
132→            return if (copyFileToCache(context, uri, tempPath)) {
133→                tempPath
134→            } else {
135→                null
136→            }
137→        }
138→
139→        /**
140→         * Makes a cached copy of the file selected on [intent] and returns its path
141→         */
142→        fun getFileCachedCopy(context: Context, intent: Intent): String? {
143→            val uri = getDataUri(intent) ?: return null
144→            return getFileCachedCopy(context, uri)
145→        }
146→
147→        private fun handleContentProviderFile(
148→            context: Context,
149→            intent: Intent,
150→            importPathUri: Uri
151→        ): ImportResult {
152→            // Note: intent.getData() can be null. Use data instead.
153→            if (!isValidImportType(context, importPathUri)) {
154→                return ImportResult.fromErrorString(context.getString(R.string.import_log_no_apkg))
155→            }
156→            // Get the original filename from the content provider URI
157→            var filename = getFileNameFromContentProvider(context, importPathUri)
158→            // Hack to fix bug where ContentResolver not returning filename correctly
159→            if (filename == null) {
160→                if (intent.type == "application/apkg" || intent.type == "application/zip") {
161→                    // Set a dummy filename if MIME type provided or is a valid zip file
162→                    filename = "unknown_filename.apkg"
163→                    Timber.w("Could not retrieve filename from ContentProvider, but was valid zip file so we try to continue")
164→                } else {
165→                    Timber.e("Could not retrieve filename from ContentProvider")
166→                    CrashReportService.sendExceptionReport(
167→                        RuntimeException("Could not import apkg from ContentProvider"),
168→                        "IntentHandler.java",
169→                        "apkg import failed; mime type ${intent.type}"
170→                    )
171→                    return ImportResult.fromErrorString(AnkiDroidApp.appResources.getString(R.string.import_error_content_provider, AnkiDroidApp.manualUrl + "#importing"))
172→                }
173→            }
174→            val tempOutDir: String
175→            if (!isValidPackageName(filename)) {
176→                return if (isAnkiDatabase(filename)) {
177→                    // .anki2 files aren't supported by Anki Desktop, we should eventually support them, because we can
178→                    // but for now, show a "nice" error.
179→                    ImportResult.fromErrorString(context.resources.getString(R.string.import_error_load_imported_database))
180→                } else {
181→                    // Don't import if file doesn't have an Anki package extension
182→                    ImportResult.fromErrorString(context.resources.getString(R.string.import_error_not_apkg_extension, filename))
183→                }
184→            } else {
185→                // Copy to temporary file
186→                filename = ensureValidLength(filename)
187→                tempOutDir = Uri.fromFile(File(context.cacheDir, filename)).encodedPath!!
188→                val errorMessage = if (copyFileToCache(context, importPathUri, tempOutDir)) {
189→                    null
190→                } else {
191→                    context.getString(R.string.import_error_copy_to_cache)
192→                }
193→                // Show import dialog
194→                if (errorMessage != null) {
195→                    CrashReportService.sendExceptionReport(
196→                        RuntimeException("Error importing apkg file"),
197→                        "IntentHandler.java",
198→                        "apkg import failed"
199→                    )
200→                    return ImportResult.fromErrorString(errorMessage)
201→                }
202→            }
203→            sendShowImportFileDialogMsg(tempOutDir)
204→            return ImportResult.fromSuccess()
205→        }
206→
207→        private fun isValidImportType(context: Context, importPathUri: Uri): Boolean {
208→            val fileName = getFileNameFromContentProvider(context, importPathUri)
209→            return when {
210→                isDeckPackage(fileName) -> true
211→                isCollectionPackage(fileName) -> true
212→                else -> false
213→            }
214→        }
215→
216→        private fun isAnkiDatabase(filename: String?): Boolean {
217→            return filename != null && hasExtension(filename, "anki2")
218→        }
219→
220→        private fun ensureValidLength(fileName: String): String {
221→            // #6137 - filenames can be too long when URLEncoded
222→            return try {
223→                val encoded = URLEncoder.encode(fileName, "UTF-8")
224→                if (encoded.length <= fileNameShorteningThreshold) {
225→                    Timber.d("No filename truncation necessary")
226→                    fileName
227→                } else {
228→                    Timber.d("Filename was longer than %d, shortening", fileNameShorteningThreshold)
229→                    // take 90 instead of 100 so we don't get the extension
230→                    val substringLength = fileNameShorteningThreshold - 10
231→                    val shortenedFileName = encoded.substring(0, substringLength) + "..." + getExtension(fileName)
232→                    Timber.d("Shortened filename '%s' to '%s'", fileName, shortenedFileName)
233→                    // if we don't decode, % is double-encoded
234→                    URLDecoder.decode(shortenedFileName, "UTF-8")
235→                }
236→            } catch (e: Exception) {
237→                Timber.w(e, "Failed to shorten file: %s", fileName)
238→                fileName
239→            }
240→        }
241→
242→        @CheckResult
243→        private fun getExtension(fileName: String): String {
244→            val file = Uri.fromFile(File(fileName))
245→            return AssetHelper.getFileExtensionFromFilePath(file.toString())
246→        }
247→
248→        protected open fun getFileNameFromContentProvider(context: Context, data: Uri): String? {
249→            var filename: String? = null
250→            try {
251→                context.contentResolver.query(
252→                    data,
253→                    arrayOf(OpenableColumns.DISPLAY_NAME),
254→                    null,
255→                    null,
256→                    null
257→                ).use { cursor ->
258→                    if (cursor != null && cursor.moveToFirst()) {
259→                        filename = cursor.getString(0)
260→                        Timber.d("handleFileImport() Importing from content provider: %s", filename)
261→                    }
262→                }
263→            } catch (e: Exception) {
264→                Timber.w(e, "Error querying content provider")
265→                filename = null // Set filename to null in case of an exception
266→            }
267→            return filename
268→        }
269→
270→        fun showImportUnsuccessfulDialog(activity: Activity, errorMessage: String?, exitActivity: Boolean) {
271→            Timber.e("showImportUnsuccessfulDialog() message %s", errorMessage)
272→            val title = activity.resources.getString(R.string.import_title_error)
273→            AlertDialog.Builder(activity).show {
274→                title(text = title)
275→                message(text = errorMessage!!)
276→                setCancelable(false)
277→                positiveButton(R.string.dialog_ok) {
278→                    if (exitActivity) {
279→                        activity.finish()
280→                    }
281→                }
282→            }
283→        }
284→
285→        /**
286→         * Copy the data from the intent to a temporary file
287→         * @param data intent from which to get input stream
288→         * @param tempPath temporary path to store the cached file
289→         * @return whether or not copy was successful
290→         */
291→        protected open fun copyFileToCache(context: Context, data: Uri?, tempPath: String): Boolean {
292→            // Get an input stream to the data in ContentProvider
293→            val inputStream: InputStream = try {
294→                context.contentResolver.openInputStream(data!!)
295→            } catch (e: FileNotFoundException) {
296→                Timber.e(e, "Could not open input stream to intent data")
297→                return false
298→            } ?: return false
299→            // Check non-null
300→            try {
301→                CompatHelper.compat.copyFile(inputStream, tempPath)
302→            } catch (e: IOException) {
303→                Timber.e(e, "Could not copy file to %s", tempPath)
304→                return false
305→            } finally {
306→                try {
307→                    inputStream.close()
308→                } catch (e: IOException) {
309→                    Timber.e(e, "Error closing input stream")
310→                }
311→            }
312→            return true
313→        }
314→
315→        companion object {
316→            fun getDataUri(intent: Intent): Uri? {
317→                if (intent.data == null) {
318→                    Timber.i("No intent data. Attempting to read clip data.")
319→                    if (intent.clipData == null || intent.clipData!!.itemCount == 0) {
320→                        return null
321→                    }
322→                    return intent.clipData?.getItemAt(0)?.uri
323→                }
324→                // If Uri is of scheme which is supported by ContentResolver, read the contents
325→                val intentUriScheme = intent.data!!.scheme
326→                return if (intentUriScheme == ContentResolver.SCHEME_CONTENT || intentUriScheme == ContentResolver.SCHEME_FILE || intentUriScheme == ContentResolver.SCHEME_ANDROID_RESOURCE) {
327→                    Timber.i("Attempting to read data from intent.")
328→                    intent.data
329→                } else {
330→                    null
331→                }
332→            }
333→
334→            /**
335→             * Send a Message to AnkiDroidApp so that the DialogMessageHandler shows the Import apkg dialog.
336→             * @param importPath path of to apkg file which will be imported
337→             */
338→            private fun sendShowImportFileDialogMsg(importPath: String) {
339→                // Get the filename from the path
340→                val filename = File(importPath).name
341→
342→                val dialogMessage = if (isCollectionPackage(filename)) {
343→                    CollectionImportReplace(importPath)
344→                } else {
345→                    CollectionImportAdd(importPath)
346→                }
347→                // Store the message in AnkiDroidApp message holder, which is loaded later in AnkiActivity.onResume
348→                DialogHandler.storeMessage(dialogMessage.toMessage())
349→            }
350→
351→            internal fun isDeckPackage(filename: String?): Boolean {
352→                return filename != null && filename.lowercase(Locale.ROOT).endsWith(".apkg") && "collection.apkg" != filename
353→            }
354→
355→            fun hasExtension(filename: String, extension: String?): Boolean {
356→                val fileParts = filename.split("\\.".toRegex()).toTypedArray()
357→                if (fileParts.size < 2) {
358→                    return false
359→                }
360→                val extensionSegment = fileParts[fileParts.size - 1]
361→                // either "apkg", or "apkg (1)".
362→                // COULD_BE_BETTE: accepts .apkgaa"
363→                return extensionSegment.lowercase(Locale.ROOT).startsWith(extension!!)
364→            }
365→        }
366→    }
367→
368→    class ImportResult(val humanReadableMessage: String?) {
369→        val isSuccess: Boolean
370→            get() = humanReadableMessage == null
371→
372→        companion object {
373→            fun fromErrorString(message: String?): ImportResult {
374→                return ImportResult(message)
375→            }
376→
377→            fun fromSuccess(): ImportResult {
378→                return ImportResult(null)
379→            }
380→        }
381→    }
