383→    /** Show confirmation dialog asking to confirm import with replace when file called "collection.apkg" */
384→    class CollectionImportReplace(private val importPath: String) : DialogHandlerMessage(
385→        which = WhichDialogHandler.MSG_SHOW_COLLECTION_IMPORT_REPLACE_DIALOG,
386→        analyticName = "ImportReplaceDialog"
387→    ) {
388→        override fun handleAsyncMessage(deckPicker: DeckPicker) {
389→            // Handle import of collection package APKG
390→            deckPicker.showImportDialog(ImportDialog.DIALOG_IMPORT_REPLACE_CONFIRM, importPath)
391→        }
392→
393→        override fun toMessage(): Message = Message.obtain().apply {
394→            data = bundleOf("importPath" to importPath)
395→            what = this@CollectionImportReplace.what
396→        }
397→
398→        companion object {
399→            fun fromMessage(message: Message): CollectionImportReplace =
400→                CollectionImportReplace(message.data.getString("importPath")!!)
401→        }
402→    }
403→
404→    /** Show confirmation dialog asking to confirm import with add */
405→    class CollectionImportAdd(private val importPath: String) : DialogHandlerMessage(
406→        WhichDialogHandler.MSG_SHOW_COLLECTION_IMPORT_ADD_DIALOG,
407→        "ImportAddDialog"
408→    ) {
409→        override fun handleAsyncMessage(deckPicker: DeckPicker) {
410→            // Handle import of deck package APKG
411→            deckPicker.showImportDialog(ImportDialog.DIALOG_IMPORT_ADD_CONFIRM, importPath)
412→        }
413→
414→        override fun toMessage(): Message = Message.obtain().apply {
415→            data = bundleOf("importPath" to importPath)
416→            what = this@CollectionImportAdd.what
417→        }
418→
419→        companion object {
420→            fun fromMessage(message: Message): CollectionImportAdd =
421→                CollectionImportAdd(message.data.getString("importPath")!!)
422→        }
423→    }
